import{_ as e,c as o,o as i,a4 as r}from"./chunks/framework.C7hkbLDc.js";const m=JSON.parse('{"title":"Robot Version Compatibility","description":"","frontmatter":{},"headers":[],"relativePath":"en/2-csharp/0-prologue/0.2-compatibility.md","filePath":"en/2-csharp/0-prologue/0.2-compatibility.md"}'),a={name:"en/2-csharp/0-prologue/0.2-compatibility.md"};function n(s,t,l,c,p,h){return i(),o("div",{"data-pagefind-body":!0},t[0]||(t[0]=[r('<h1 id="robot-version-compatibility" tabindex="-1">Robot Version Compatibility <a class="header-anchor" href="#robot-version-compatibility" aria-label="Permalink to “Robot Version Compatibility”">​</a></h1><p>The SDK supports Agilebot Scara, Puma, and collaborative robot series. It must be used with devices that have the robot software installed and is compatible with the robot software versions. Some functions may return different results due to version differences.</p><p>When the SDK connects to the robotic arm, it will check the version of the robotic arm motion control software. If the version is lower than the minimum requirement, the connection will fail. If it is lower than the recommended version, a prompt indicating that the version is too low will appear. Please update the robot software version in a timely manner.</p><p>Some interfaces of the SDK only support the corresponding version of the controller. Please check the compatibility of specific interfaces.</p><table tabindex="0"><thead><tr><th>SDK Version</th><th>Robot Software Version</th></tr></thead><tbody><tr><td>1.0.0.X</td><td>Copper v7.6.X.X, Bronze v7.5.X.X</td></tr></tbody></table>',5)]))}const b=e(a,[["render",n]]);export{m as __pageData,b as default};
